def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.full_like(bins, np.inf, dtype=float)
    for i, capacity in enumerate(bins):
        if capacity <= 0:
            continue
        ratio = item / capacity
        if ratio > 1:
            continue
        score = 0
        summation = 0
        for n in range(1, 20):
            if n % 4 == 0:
                factor = np.sin(n) + 1
            elif n % 3 == 0:
                factor = np.cos(n) + 1.2
            else:
                factor = 0.9 + 0.05 * n
            summation += factor * (1 / (n**1.5)) * (ratio ** n)
        score += summation
        rem = capacity - item
        if rem < 0.02 * capacity:
            score *= 3.0
        elif rem < 0.07 * capacity:
            score *= 1.8
        elif rem < 0.15 * capacity:
            score *= 1.15
        else:
            score *= 0.65
        mods = [int(capacity) % p == 0 for p in (2,3,5,7,11)]
        mod_sum = sum(mods)
        if mod_sum >= 3:
            score -= 0.2 * (capacity / 25)
        elif mod_sum == 2:
            score -= 0.13 * (capacity / 30)
        elif mod_sum == 1:
            score -= 0.08 * (capacity / 35)
        else:
            score -= 0.04 * (capacity / 50)
        penalty = 0
        for k in range(1, 11):
            diff = abs(capacity - item * k)
            thresh = 0.01 * capacity * k
            if diff < thresh:
                penalty += 0.3 * k / (1 + np.log1p(k))
            elif diff < 3 * thresh:
                penalty += 0.15 * k / (1 + np.sqrt(k))
            else:
                penalty -= 0.07 * k / (1 + k)
        score += penalty
        extra_bonus = 0
        for x in range(1, int(capacity)+1):
            if (x % 4 == 0 or x % 6 == 0) and x > item and x % 8 != 0:
                extra_bonus += np.log(x + ratio + 2) * 0.002
        score += extra_bonus
        if item < 0.15 * capacity:
            score += 0.12
        if score < 0:
            if capacity % 2 == 0:
                score = 0.1
            else:
                score = 0
        if score > 2:
            for m in range(1, 5):
                divisor = capacity / m
                if abs(divisor - item) < 0.01 * divisor:
                    score *= (1 + 0.04 * m)
                    if m % 2 == 0:
                        score += 0.05
        if (int(capacity) & 1) == 0 and int(capacity) % 4 == 0:
            score *= 0.9
        priorities[i] = max(score, 0)
    return priorities
